import axios from 'axios';
import mongoose from 'mongoose';
import User from './src/models/User.js';
import UserTopicProgression from './src/models/UserTopicProgression.js';
import Topic from './src/models/Topic.js';
import GeneratedQuestionLog from './src/models/GeneratedQuestionLog.js';
import PracticeAttemptEvent from './src/models/PracticeAttemptEvent.js';

const API_URL = 'http://localhost:8000';
const email = 'shreyash@gmail.com';
const password = '123456';

let authToken = null;
let userId = null;
let dbConnected = false;

// ============ UTILITIES ============
function printSeparator(title) {
  console.log('\n╔' + '═'.repeat(72) + '╗');
  console.log('║ ' + title.padEnd(70) + ' ║');
  console.log('╚' + '═'.repeat(72) + '╝\n');
}

function printSubheader(title) {
  console.log('\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  console.log(`📌 ${title}`);
  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n');
}

function prettifyJSON(obj, indent = 2) {
  return JSON.stringify(obj, null, indent);
}

// ============ MONGODB CONNECTION ============
async function connectDB() {
  try {
    const mongoDB = process.env.MONGODB_URI || 'mongodb://localhost:27017/prepmate-ai';
    await mongoose.connect(mongoDB);
    dbConnected = true;
    console.log('✅ Connected to MongoDB');
  } catch (error) {
    console.warn('⚠️  MongoDB connection failed (will try API tests only)');
    dbConnected = false;
  }
}

// ============ API TESTS ============

async function login() {
  printSubheader('Step 1: User Login');
  
  try {
    const response = await axios.post(`${API_URL}/api/auth/login`, {
      email,
      password,
    });

    authToken = response.data.token;
    userId = response.data.user._id;

    console.log('✅ Login Successful\n');
    console.log('User Details:');
    console.log(prettifyJSON(response.data.user, 2));

    return true;
  } catch (error) {
    console.error('❌ Login failed:');
    if (error.response?.data) {
      console.error(error.response.data);
    } else {
      console.error(error.message);
    }
    return false;
  }
}

async function fetchUserProfile() {
  printSubheader('Step 2: Detailed User Profile Data (Sent to LLM)');
  
  try {
    const user = await User.findById(userId).lean();
    
    if (!user) {
      console.error('❌ User not found');
      return null;
    }

    console.log('📋 USER PROFILE DATA SENT TO LLM:\n');
    console.log(prettifyJSON(user, 2));

    // Highlight key fields used by LLM
    console.log('\n🔑 KEY FIELDS FOR LLM PROMPT:\n');
    const llmFields = {
      'User ID': user._id,
      'Name': user.name,
      'Email': user.email,
      'Learning Level': user.learningLevel,
      'Target Companies': user.targetCompaniesArray || [],
      'Preparation Phase': user.preparationPhase,
      'Preparation Timeline': user.preparationTimeline,
      'Experience Level': user.experienceLevel,
      'Target Roles': user.targetRoles,
      'Goals': user.goals,
      'Language Preferences': user.languagePreferences || [],
    };

    Object.entries(llmFields).forEach(([key, value]) => {
      if (value !== undefined && value !== null && value !== '') {
        console.log(`  • ${key}: ${JSON.stringify(value)}`);
      }
    });

    return user;
  } catch (error) {
    console.error('❌ Error fetching user profile:');
    console.error(error.message);
    return null;
  }
}

async function fetchUserProgress() {
  printSubheader('Step 3: User Topic Progression');
  
  try {
    if (!dbConnected) {
      console.log('⚠️  Database not connected, skipping...');
      return null;
    }

    const progressions = await UserTopicProgression.find({ userId }).lean();
    
    console.log(`Found ${progressions.length} topic progressions\n`);

    if (progressions.length > 0) {
      const sample = progressions.slice(0, 3);
      sample.forEach((prog, idx) => {
        console.log(`Topic ${idx + 1}: ${prog.topicId}`);
        console.log(prettifyJSON(prog, 2));
        console.log('');
      });
    }

    return progressions;
  } catch (error) {
    console.error('❌ Error fetching progression:');
    console.error(error.message);
    return null;
  }
}

async function fetchUserAttempts() {
  printSubheader('Step 4: Recent Practice Attempts (For Mistake Analysis)');
  
  try {
    if (!dbConnected) {
      console.log('⚠️  Database not connected, skipping...');
      return null;
    }

    const attempts = await PracticeAttemptEvent.find({ userId })
      .sort({ createdAt: -1 })
      .limit(10)
      .lean();

    console.log(`Found ${attempts.length} recent practice attempts\n`);

    if (attempts.length > 0) {
      const sample = attempts.slice(0, 3);
      sample.forEach((attempt, idx) => {
        console.log(`Attempt ${idx + 1}:`);
        console.log(prettifyJSON({
          topicId: attempt.topicId,
          result: attempt.result,
          timeSpent: attempt.timeSpent,
          mistakeType: attempt.mistakeType,
          createdAt: attempt.createdAt,
        }, 2));
        console.log('');
      });
    }

    return attempts;
  } catch (error) {
    console.error('❌ Error fetching attempts:');
    console.error(error.message);
    return null;
  }
}

async function generateQuestions() {
  printSubheader('Step 5: Generate Questions via LLM');
  
  try {
    // First, get a topic
    const topicsResponse = await axios.get(`${API_URL}/api/practice/topics`, {
      headers: { 'Authorization': `Bearer ${authToken}` },
    });

    const topics = topicsResponse.data.data || topicsResponse.data.topics || [];
    if (topics.length === 0) {
      console.error('❌ No topics found');
      return null;
    }

    const topicId = topics[0]?.topicId || 'arrays';
    console.log(`Selected topic: ${topicId}\n`);

    // Generate questions
    console.log('🤖 Calling Gemini LLM to generate questions...\n');
    const response = await axios.post(
      `${API_URL}/api/practice/topics/${topicId}/generate-questions`,
      { limit: 5 },
      {
        headers: { 'Authorization': `Bearer ${authToken}` },
      }
    );

    const data = response.data.data || response.data;

    console.log('✅ Question Generation Response:\n');
    console.log(prettifyJSON(data, 2));

    // Detailed analysis
    if (data.generationPrompt) {
      printSubheader('Learner Profile Sent to Gemini');
      console.log(prettifyJSON(data.generationPrompt, 2));
    }

    if (data.questions && data.questions.length > 0) {
      printSubheader(`Generated Questions (${data.questions.length} total)`);
      
      data.questions.forEach((q, idx) => {
        console.log(`\n📝 Question ${idx + 1}:`);
        console.log(`  Title: ${q.problemTitle}`);
        console.log(`  Difficulty: ${q.difficulty}`);
        console.log(`  Topic: ${q.topic}`);
        console.log(`  Concept Tested: ${q.primaryConceptTested || 'Unknown'}`);
        console.log(`  Why Recommended: ${q.whyRecommended || 'No reason provided'}`);
        console.log(`  Platform: ${q.platform || 'Unknown'}`);
        console.log(`  URL: ${q.sourceUrl || 'No URL'}`);
        console.log(`  Duplicate?: ${q.isDuplicate ? 'Yes ⚠️' : 'No ✅'}`);
      });
    }

    return { topicId, generationData: data };
  } catch (error) {
    console.error('❌ Question generation failed:');
    if (error.response?.data) {
      console.error(error.response.data);
    } else {
      console.error(error.message);
    }
    return null;
  }
}

// ============ DATABASE SCHEMA INSPECTION ============

async function inspectDatabaseSchema() {
  printSubheader('Step 6: Database Schema Inspection');
  
  if (!dbConnected) {
    console.log('⚠️  Database not connected, skipping...');
    return;
  }

  try {
    console.log('📊 GeneratedQuestionLog Schema:\n');
    const schema = GeneratedQuestionLog.schema.paths;
    const fields = Object.keys(schema).filter(k => !k.startsWith('_'));
    
    console.log('Fields in schema:');
    fields.forEach(field => {
      const fieldInfo = schema[field];
      console.log(`  • ${field}: ${fieldInfo.instance} ${fieldInfo.options?.index ? '(indexed)' : ''}${fieldInfo.options?.required ? '(required)' : ''}`);
    });

    console.log('\n\n📊 Sample GeneratedQuestionLog Documents:\n');
    const logs = await GeneratedQuestionLog.find({ userId }).lean().limit(3);
    
    if (logs.length > 0) {
      logs.forEach((log, idx) => {
        console.log(`Document ${idx + 1}:`);
        console.log(prettifyJSON({
          _id: log._id,
          problemTitle: log.problemTitle,
          topicId: log.topicId,
          difficulty: log.difficulty,
          isPaired: log.isPaired,
          userResponse: log.userResponse,
          createdAt: log.createdAt,
          source: log.source,
        }, 2));
        console.log('');
      });
    } else {
      console.log('❌ No documents found in GeneratedQuestionLog for this user');
    }
  } catch (error) {
    console.error('❌ Error inspecting schema:');
    console.error(error.message);
  }
}

async function verifyDatabaseStorage(generationResult) {
  printSubheader('Step 7: Verify Questions Stored in Database');
  
  if (!dbConnected || !generationResult) {
    console.log('⚠️  Cannot verify (DB not connected or no generation data)');
    return;
  }

  try {
    const { topicId, generationData } = generationResult;
    
    // Wait a moment for database writes
    await new Promise(resolve => setTimeout(resolve, 2000));

    const storedLogs = await GeneratedQuestionLog.find({
      userId,
      topicId,
    }).sort({ createdAt: -1 }).lean();

    console.log(`✅ Found ${storedLogs.length} questions stored in database\n`);

    if (storedLogs.length > 0) {
      console.log('Stored Questions:\n');
      storedLogs.slice(0, 5).forEach((log, idx) => {
        console.log(`${idx + 1}. ${log.problemTitle}`);
        console.log(`   Difficulty: ${log.difficulty}`);
        console.log(`   Topic: ${log.topic || log.topicId}`);
        console.log(`   Source: ${log.source || 'Unknown'}`);
        console.log(`   DB Paired: ${log.isPaired ? '✅ Yes' : '❌ No'}`);
        console.log(`   User Attempted: ${log.userResponse?.attempted ? '✅ Yes' : '❌ No'}`);
        console.log(`   Stored At: ${log.createdAt || 'Unknown'}`);
        console.log('');
      });

      // Compare with generated data
      if (generationData.questions) {
        console.log('\n📊 Comparison with Generated Data:\n');
        const generatedTitles = generationData.questions.map(q => q.problemTitle.toLowerCase());
        const storedTitles = storedLogs.map(q => q.problemTitle.toLowerCase());

        console.log(`Generated: ${generatedTitles.length} questions`);
        console.log(`Stored: ${storedTitles.length} questions`);

        const matching = storedTitles.filter(t => generatedTitles.includes(t)).length;
        console.log(`Matching: ${matching} questions\n`);

        if (matching === storedTitles.length) {
          console.log('✅ All stored questions match generated questions');
        } else {
          console.log('⚠️  Some stored questions do not match generated data');
        }
      }
    }
  } catch (error) {
    console.error('❌ Error verifying storage:');
    console.error(error.message);
  }
}

// ============ ANALYSIS ============

async function analyzeQuestionGeneration(generationResult) {
  printSubheader('Step 8: Analysis - Why These Questions?');
  
  if (!generationResult) {
    console.log('❌ No generation data available');
    return;
  }

  const { generationData } = generationResult;

  if (!generationData.questions || generationData.questions.length === 0) {
    console.log('❌ No questions generated');
    return;
  }

  console.log('🔍 Question Generation Reasoning:\n');

  generationData.questions.forEach((q, idx) => {
    console.log(`Question ${idx + 1}: ${q.problemTitle}\n`);
    console.log(`Reasoning for this question:`);
    console.log(`  1. Difficulty Level: ${q.difficulty}`);
    console.log(`     └─ Preferred Level: ${generationData.generationPrompt?.recommendedDifficulty}`);
    console.log(`  2. Concept Category: ${q.primaryConceptTested || 'General'}`);
    console.log(`     └─ Weak Subtopics: ${generationData.generationPrompt?.weakSubtopics}`);
    console.log(`  3. Why Generated:`);
    console.log(`     ${q.whyRecommended || '     └─ (No specific reason provided)'}`);
    console.log(`  4. Source: ${generationData.source || 'Unknown'}`);
    console.log(`  5. Duplicate: ${q.isDuplicate ? 'Yes (Already assigned)' : 'No (New)'}`);
    console.log('');
  });

  // Stats
  console.log('\n📊 Overall Generation Stats:\n');
  const duplicates = generationData.questions.filter(q => q.isDuplicate).length;
  const newQuestions = generationData.questions.filter(q => !q.isDuplicate).length;
  const difficulties = [...new Set(generationData.questions.map(q => q.difficulty))];

  console.log(`  • New Questions: ${newQuestions}`);
  console.log(`  • Duplicates Detected: ${duplicates}`);
  console.log(`  • Difficulty Range: ${difficulties.join(', ')}`);
  console.log(`  • Generation Timestamp: ${generationData.generatedAt || 'Unknown'}`);
}

// ============ MAIN EXECUTION ============

async function runComprehensiveTests() {
  printSeparator('COMPREHENSIVE LLM QUESTION GENERATION TEST');
  console.log(`Testing user: ${email}`);
  console.log(`API URL: ${API_URL}\n`);

  try {
    // Connect to DB
    await connectDB();

    // Step 1: Login
    const loginSuccess = await login();
    if (!loginSuccess) {
      console.error('\n❌ Cannot continue without login');
      return;
    }

    // Step 2: Fetch user profile
    const userProfile = await fetchUserProfile();

    // Step 3: Fetch user progress
    const userProgress = await fetchUserProgress();

    // Step 4: Fetch recent attempts
    const recentAttempts = await fetchUserAttempts();

    // Step 5: Generate questions
    const generationResult = await generateQuestions();

    // Step 6: Inspect database schema
    await inspectDatabaseSchema();

    // Step 7: Verify database storage
    if (generationResult) {
      await verifyDatabaseStorage(generationResult);
    }

    // Step 8: Analysis
    if (generationResult) {
      await analyzeQuestionGeneration(generationResult);
    }

    // Final summary
    printSeparator('TEST SUMMARY');
    console.log('✅ All tests completed successfully!\n');
    console.log('Next Steps:');
    console.log('  1. Check ai-services logs for Gemini API response');
    console.log('  2. Verify GEMINI_API_KEY is set in ai-services/.env');
    console.log('  3. Monitor GeneratedQuestionLog collection growth');
    console.log('  4. Test deduplication by generating again\n');

  } catch (error) {
    console.error('\n❌ CRITICAL ERROR:');
    console.error(error.message);
    console.error(error.stack);
  } finally {
    if (dbConnected) {
      await mongoose.connection.close();
      console.log('\n✅ Database connection closed');
    }
    process.exit(0);
  }
}

// Run tests
await runComprehensiveTests();
